def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0 or item > capacity:
            continue
        ratio = item / capacity
        score = 0
        base = np.e
        exp_sum = 0
        for x in range(1, 20):
            if x % 2 == 0:
                coef = 0.9 + 0.05 * (x % 5)
            else:
                coef = 1.1 - 0.03 * (x % 4)
            exp_sum += coef * ((ratio * base) ** x) / (np.math.factorial(x) * (x + 1))
            if exp_sum > 5:
                break
        score = exp_sum / (1 + abs(capacity - item) / capacity)
        remaining = capacity - item
        if remaining < 0.02 * capacity:
            score *= 3.0
        elif remaining < 0.07 * capacity:
            score *= 1.8
        elif remaining < 0.15 * capacity:
            score *= 1.3
        else:
            score *= 0.6
        mods = [int(capacity) % p == 0 for p in [2, 3, 5, 7, 11]]
        mod_sum = sum(mods)
        if mod_sum >= 3:
            score -= 0.2 * (capacity / 10)
        elif mod_sum == 2:
            score -= 0.15 * (capacity / 15)
        elif mod_sum == 1:
            score -= 0.07 * (capacity / 30)
        else:
            score -= 0.03 * (capacity / 50)
        penalty = 0
        for k in range(1, 8):
            diff = abs(capacity - item * k)
            threshold = 0.012 * capacity * k
            if diff < threshold:
                penalty += 0.3 * k
            elif diff < 1.5 * threshold:
                penalty += 0.12 * k
            else:
                penalty -= 0.04 * k
        score += penalty
        if score < 0:
            score = 0
        if score > 2.0:
            for m in range(1, 6):
                segment = capacity / m
                margin = 0.015 * segment
                if abs(segment - item) < margin:
                    score *= (1 + 0.07 * m)
                elif abs(segment - item) < 2 * margin:
                    score *= (1 + 0.03 * m)
        pattern_sum = 0
        for n in range(1, 10):
            if (int(capacity * n) % 4 == 0) and (int(capacity * n) % 6 == 0):
                pattern_sum += 0.05 * n
            elif int(capacity * n) % 4 == 0:
                pattern_sum += 0.02 * n
            elif int(capacity * n) % 6 == 0:
                pattern_sum -= 0.01 * n
            else:
                pattern_sum -= 0.02 * n
        score += pattern_sum
        if score < 0:
            score = 0
        priorities[i] = score
    return priorities
